#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int idx[N];
        for (int i = 0; i < N; i++) {
            idx[i] = i;
        }
        qsort(idx, N, sizeof(int), compare);
        for (int i = 0; i < N; i++) {
            if (K > 0 && B[idx[i]] > 0) {
                int inc = (K < abs(A[idx[i]])) ? K : abs(A[idx[i]]);
                A[idx[i]] += inc;
                K -= inc;
            } else if (K > 0 && B[idx[i]] < 0) {
                int dec = (K < abs(A[idx[i]])) ? K : abs(A[idx[i]]);
                A[idx[i]] -= dec;
                K -= dec;
            }
        }
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            sum += (long long)A[i] * B[i];
        }
        printf("%lld\n", sum);
    }
    return 0;
}

