import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            Integer[] idx = new Integer[N];
            for (int i = 0; i < N; i++) {
                idx[i] = i;
            }
            Arrays.sort(idx, (a, b) -> B[b] - B[a]);
            for (int i = 0; i < N; i++) {
                if (K > 0 && B[idx[i]] > 0) {
                    int inc = (K < Math.abs(A[idx[i]])) ? K : Math.abs(A[idx[i]]);
                    A[idx[i]] += inc;
                    K -= inc;
                } else if (K > 0 && B[idx[i]] < 0) {
                    int dec = (K < Math.abs(A[idx[i]])) ? K : Math.abs(A[idx[i]]);
                    A[idx[i]] -= dec;
                    K -= dec;
                }
            }
            long sum = 0;
            for (int i = 0; i < N; i++) {
                sum += (long) A[i] * B[i];
            }
            System.out.println(sum);
        }
    }
}

